import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  PhotoIcon,
  MapPinIcon,
  ExclamationTriangleIcon,
  CheckCircleIcon,
  HomeIcon,
  ClockIcon,
  PlusCircleIcon,
  UserIcon,
  ArrowRightOnRectangleIcon,
  Bars3Icon,
  XMarkIcon
} from '@heroicons/react/24/outline';
import { Link } from 'react-router-dom';

const ComplaintSubmission = () => {
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    category: '',
    location: '',
    latitude: '',
    longitude: '',
    priority: 'medium',
    images: []
  });
  const [loading, setLoading] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const [error, setError] = useState('');
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [fetchingLocation, setFetchingLocation] = useState(false);
  const [user, setUser] = useState(JSON.parse(localStorage.getItem('user') || '{}'));
  const navigate = useNavigate();

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    navigate('/login');
  };

  const categories = [
    'Infrastructure',
    'Sanitation',
    'Water Supply',
    'Electricity',
    'Roads',
    'Public Safety',
    'Noise Pollution',
    'Other'
  ];

  const priorities = [
    { value: 'low', label: 'Low', color: 'bg-green-100 text-green-800' },
    { value: 'medium', label: 'Medium', color: 'bg-yellow-100 text-yellow-800' },
    { value: 'high', label: 'High', color: 'bg-red-100 text-red-800' }
  ];

  const handleChange = (e) => {
    const { name, value } = e.target;
    setError('');
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleImageUpload = (e) => {
    const files = Array.from(e.target.files);
    setFormData(prev => ({
      ...prev,
      images: [...prev.images, ...files]
    }));
  };

  const getCurrentLocation = () => {
    if (!navigator.geolocation) {
      toast.error('Geolocation is not supported by your browser');
      return;
    }

    setFetchingLocation(true);
    navigator.geolocation.getCurrentPosition(
      async (position) => {
        const { latitude, longitude } = position.coords;
        try {
          // Reverse geocoding using Nominatim (OpenStreetMap)
          const response = await fetch(
            `https://nominatim.openstreetmap.org/reverse?format=json&lat=${latitude}&lon=${longitude}&zoom=18&addressdetails=1`
          );
          const data = await response.json();
          const address = data.display_name || `${latitude.toFixed(6)}, ${longitude.toFixed(6)}`;

          setFormData(prev => ({
            ...prev,
            location: address,
            latitude: latitude.toString(),
            longitude: longitude.toString()
          }));
        } catch (error) {
          console.error('Reverse geocoding error:', error);
          setFormData(prev => ({
            ...prev,
            latitude: latitude.toString(),
            longitude: longitude.toString()
          }));
        } finally {
          setFetchingLocation(false);
        }
      },
      (error) => {
        setFetchingLocation(false);
        console.error('Geolocation error:', error);
      }
    );
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    try {
      const token = localStorage.getItem('token');
      if (!token) {
        setError('You must be logged in to submit a complaint');
        setLoading(false);
        return;
      }

      const submissionData = new FormData();
      submissionData.append('title', formData.title);
      submissionData.append('description', formData.description);
      submissionData.append('category', formData.category);
      submissionData.append('priority', formData.priority);
      submissionData.append('location[address]', formData.location);
      submissionData.append('location[latitude]', formData.latitude);
      submissionData.append('location[longitude]', formData.longitude);

      if (formData.images && formData.images.length > 0) {
        formData.images.forEach((image) => {
          submissionData.append('images', image);
        });
      }

      const response = await fetch('http://localhost:5000/api/complaints', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`
        },
        body: submissionData
      });

      const data = await response.json();

      if (response.ok) {
        setSubmitted(true);
        setFormData({
          title: '',
          description: '',
          category: '',
          priority: 'medium',
          location: '',
          latitude: '',
          longitude: '',
          images: []
        });
      } else {
        setError(data.message || 'Failed to submit complaint');
      }
    } catch (error) {
      console.error('Submission error:', error);
      setError('Network error. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  if (submitted) {
    return (
      <div className="flex h-screen bg-gray-50 overflow-hidden font-sans">
        {/* Sidebar */}
        <aside className="fixed inset-y-0 left-0 z-40 w-72 bg-white/80 backdrop-blur-xl border-r border-blue-100/50 shadow-2xl lg:relative lg:translate-x-0">
          <div className="h-full flex flex-col p-8 bg-gradient-to-br from-blue-50/30 to-white/50">
            <Link to="/" className="flex items-center space-x-3 group relative mb-8">
              <div className="relative w-11 h-11 bg-gradient-to-tr from-blue-600 to-indigo-600 rounded-xl flex items-center justify-center shadow-lg">
                <MapPinIcon className="h-6 w-6 text-white" />
              </div>
              <div className="relative text-left">
                <h1 className="text-xl font-bold text-gray-900 tracking-tight leading-none">
                  Urban<span className="text-blue-600 bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-indigo-600">Insights</span>
                </h1>
                <p className="text-xs font-medium text-blue-500 mt-1 opacity-80">Citizen Portal</p>
              </div>
            </Link>
          </div>
        </aside>

        <main className="flex-1 flex flex-col justify-center py-12 sm:px-6 lg:px-8 bg-gray-50">
          <div className="sm:mx-auto sm:w-full sm:max-w-md">
            <div className="bg-white/80 backdrop-blur-xl py-10 px-8 border border-blue-50/50 shadow-2xl rounded-[2.5rem] text-center">
              <div className="w-20 h-20 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center mx-auto mb-6">
                <CheckCircleIcon className="h-10 w-10" />
              </div>
              <h2 className="text-3xl font-semibold text-gray-900 tracking-tight mb-2">Submitted!</h2>
              <p className="text-gray-500 mb-8 font-medium">
                Your report has been successfully logged. We'll keep you posted on the status.
              </p>
              <div className="space-y-4">
                <button
                  onClick={() => navigate('/dashboard')}
                  className="w-full py-4 px-6 bg-gradient-to-r from-blue-600 to-indigo-600 text-white rounded-2xl text-sm font-semibold shadow-xl shadow-blue-200 active:scale-95 transition-all"
                >
                  Dashboard
                </button>
                <button
                  onClick={() => {
                    setSubmitted(false);
                    setFormData({
                      title: '',
                      description: '',
                      category: '',
                      location: '',
                      latitude: '',
                      longitude: '',
                      priority: 'medium',
                      images: []
                    });
                  }}
                  className="w-full py-4 px-6 bg-white border border-gray-100 text-gray-500 rounded-2xl text-sm font-semibold hover:text-gray-900 active:scale-95 transition-all"
                >
                  Report Another
                </button>
              </div>
            </div>
          </div>
        </main>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-gray-50 overflow-hidden font-sans">
      {/* Mobile Sidebar Toggle */}
      <div className="lg:hidden fixed bottom-6 right-6 z-50">
        <button
          onClick={() => setIsMenuOpen(!isMenuOpen)}
          className="p-4 bg-blue-600 text-white rounded-full shadow-2xl hover:bg-blue-700 transition-all active:scale-95"
        >
          {isMenuOpen ? <XMarkIcon className="h-6 w-6" /> : <Bars3Icon className="h-6 w-6" />}
        </button>
      </div>

      {/* Sidebar */}
      <aside className={`fixed inset-y-0 left-0 z-40 w-72 bg-white/80 backdrop-blur-xl border-r border-blue-100/50 shadow-2xl shadow-blue-500/5 transform transition-all duration-500 ease-[cubic-bezier(0.23,1,0.32,1)] lg:relative lg:translate-x-0 ${isMenuOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="h-full flex flex-col">
          {/* Logo Section */}
          <div className="p-8 border-b border-blue-50/50 bg-gradient-to-br from-blue-50/30 to-white/50">
            <Link to="/" className="flex items-center space-x-3 group relative">
              <div className="absolute -inset-2 bg-blue-100/20 rounded-2xl scale-75 opacity-0 group-hover:opacity-100 group-hover:scale-110 transition-all duration-500 blur-xl"></div>
              <div className="relative w-11 h-11 bg-gradient-to-tr from-blue-600 to-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-blue-200 group-hover:shadow-blue-300 transition-all duration-500 group-hover:-rotate-6">
                <MapPinIcon className="h-6 w-6 text-white" />
              </div>
              <div className="relative text-left">
                <h1 className="text-xl font-bold text-gray-900 tracking-tight leading-none">
                  Urban<span className="text-blue-600 bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-indigo-600">Insights</span>
                </h1>
                <p className="text-xs font-medium text-blue-500 mt-1 opacity-80">Citizen Portal</p>
              </div>
            </Link>
          </div>

          {/* User Profile Section */}
          <div className="px-6 py-8">
            <div className="p-4 bg-gradient-to-br from-blue-50/50 to-indigo-50/50 rounded-[1.5rem] border border-blue-100/50 flex items-center space-x-4">
              <div className="relative w-12 h-12 bg-white rounded-full flex items-center justify-center border-2 border-blue-100 shadow-sm flex-shrink-0">
                <UserIcon className="h-6 w-6 text-blue-600" />
              </div>
              <div className="flex-1 min-w-0 text-left">
                <p className="text-sm font-semibold text-gray-900 truncate">{user?.name || 'Citizen User'}</p>
                <p className="text-[11px] font-medium text-blue-500/80 truncate">{user?.email || 'Authenticated'}</p>
              </div>
            </div>
          </div>

          {/* Navigation Links */}
          <nav className="flex-1 px-4 py-2 space-y-1.5 overflow-y-auto custom-scrollbar">
            <Link to="/dashboard" className="group flex items-center space-x-3 px-5 py-4 text-gray-500 hover:bg-blue-50 hover:text-blue-700 rounded-2xl font-semibold transition-all duration-300 hover:translate-x-1">
              <HomeIcon className="h-5 w-5 text-gray-400 group-hover:text-blue-600 transition-colors" />
              <span className="tracking-tight">Overview</span>
            </Link>
            <Link to="/complaint-history" className="group flex items-center space-x-3 px-5 py-4 text-gray-500 hover:bg-blue-50 hover:text-blue-700 rounded-2xl font-semibold transition-all duration-300 hover:translate-x-1">
              <ClockIcon className="h-5 w-5 text-gray-400 group-hover:text-blue-600 transition-colors" />
              <span className="tracking-tight">Complaint History</span>
            </Link>
            <Link to="/submit-complaint" className="group flex items-center space-x-3 px-5 py-4 bg-gradient-to-r from-blue-600 to-indigo-600 text-white rounded-2xl font-semibold shadow-lg shadow-blue-500/20 transition-all duration-300 hover:scale-[1.02] active:scale-95">
              <PlusCircleIcon className="h-5 w-5 transition-transform group-hover:scale-110" />
              <span className="tracking-tight">New Incident</span>
            </Link>
          </nav>

          {/* Sign Out Section */}
          <div className="p-6">
            <button onClick={handleLogout} className="w-full group flex items-center justify-center space-x-2 py-4 px-4 rounded-2xl text-[13px] font-semibold text-red-500 hover:text-white hover:bg-red-500 border border-red-100/50 transition-all duration-300 bg-white/50 backdrop-blur-sm">
              <ArrowRightOnRectangleIcon className="h-5 w-5 transition-transform group-hover:-translate-x-1" />
              <span>Sign Out</span>
            </button>
          </div>
        </div>
      </aside>

      {/* Overlay */}
      {isMenuOpen && (
        <div className="lg:hidden fixed inset-0 bg-gray-900/40 backdrop-blur-sm z-30 transition-opacity" onClick={() => setIsMenuOpen(false)}></div>
      )}

      {/* Main Content */}
      <main className="flex-1 h-full overflow-y-auto bg-gray-50">
        <div className="max-w-2xl mx-auto py-12 px-4 sm:px-6 lg:px-8">
          {error && (
            <div className="mb-8 p-4 bg-red-50 border-l-4 border-red-500 rounded-r-2xl shadow-sm animate-shake">
              <div className="flex items-center">
                <ExclamationTriangleIcon className="h-6 w-6 text-red-500 mr-3" />
                <div>
                  <h3 className="text-sm font-semibold text-red-800 uppercase tracking-wider">Submission Error</h3>
                  <p className="text-xs text-red-600 font-medium mt-0.5">{error}</p>
                </div>
              </div>
            </div>
          )}

          <div className="bg-white/80 backdrop-blur-xl shadow-2xl shadow-blue-500/5 rounded-[2.5rem] border border-blue-50/50 overflow-hidden">
            <div className="px-8 py-10 sm:p-12">
              <div className="mb-10 text-center">
                <div className="inline-flex p-4 rounded-3xl bg-blue-50 text-blue-600 mb-4 animate-bounce-subtle">
                  <ExclamationTriangleIcon className="h-8 w-8" />
                </div>
                <h2 className="text-3xl font-semibold text-gray-900 tracking-tight">Report Incident</h2>
                <p className="text-gray-500 mt-2 font-medium">Help us keep our city humming. Share the details below.</p>
              </div>

              <form onSubmit={handleSubmit} className="space-y-8">
                <div className="space-y-6">
                  <div>
                    <label htmlFor="title" className="block text-[10px] font-semibold text-gray-400 uppercase tracking-wider ml-1 mb-2">Complaint Title</label>
                    <input type="text" name="title" id="title" required className="block w-full px-5 py-4 bg-gray-50/50 border border-gray-100 rounded-2xl text-gray-900 font-medium focus:outline-none focus:ring-2 focus:ring-blue-500/20 transition-all" placeholder="What's the issue?" value={formData.title} onChange={handleChange} />
                  </div>
                  <div>
                    <label htmlFor="category" className="block text-[10px] font-semibold text-gray-400 uppercase tracking-wider ml-1 mb-2">Category</label>
                    <div className="relative">
                      <select id="category" name="category" required className="block w-full px-5 py-4 bg-gray-50/50 border border-gray-100 rounded-2xl text-gray-900 font-medium appearance-none focus:outline-none focus:ring-2 focus:ring-blue-500/20 transition-all" value={formData.category} onChange={handleChange}>
                        <option value="">Select Category</option>
                        {categories.map((c) => (<option key={c} value={c}>{c}</option>))}
                      </select>
                      <div className="absolute inset-y-0 right-0 flex items-center pr-4 pointer-events-none">
                        <PlusCircleIcon className="h-5 w-5 text-gray-400 rotate-45" />
                      </div>
                    </div>
                  </div>
                  <div>
                    <label htmlFor="description" className="block text-[10px] font-semibold text-gray-400 uppercase tracking-wider ml-1 mb-2">Description</label>
                    <textarea id="description" name="description" rows={4} required className="block w-full px-5 py-4 bg-gray-50/50 border border-gray-100 rounded-2xl text-gray-900 font-medium focus:outline-none focus:ring-2 focus:ring-blue-500/20 transition-all" placeholder="Tell us exactly what happened..." value={formData.description} onChange={handleChange} />
                  </div>
                  <div>
                    <label htmlFor="location" className="block text-[10px] font-semibold text-gray-400 uppercase tracking-wider ml-1 mb-2">Location</label>
                    <div className="flex gap-2">
                      <input type="text" name="location" id="location" required className="flex-1 px-5 py-4 bg-gray-50/50 border border-gray-100 rounded-2xl text-gray-900 font-medium" placeholder="Address or Landmark" value={formData.location} onChange={handleChange} />
                      <button type="button" onClick={getCurrentLocation} disabled={fetchingLocation} className="p-4 bg-blue-50 text-blue-600 rounded-2xl hover:bg-blue-100 active:scale-95 transition-all shadow-sm">
                        <MapPinIcon className={`h-6 w-6 ${fetchingLocation ? 'animate-bounce' : ''}`} />
                      </button>
                    </div>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="block text-[10px] font-semibold text-gray-400 uppercase tracking-wider ml-1 mb-2">Latitude</label>
                      <input type="text" className="w-full px-5 py-4 bg-gray-50/50 border border-gray-100 rounded-2xl text-gray-900 font-medium outline-none opacity-60" value={formData.latitude} readOnly placeholder="0.000000" />
                    </div>
                    <div>
                      <label className="block text-[10px] font-semibold text-gray-400 uppercase tracking-wider ml-1 mb-2">Longitude</label>
                      <input type="text" className="w-full px-5 py-4 bg-gray-50/50 border border-gray-100 rounded-2xl text-gray-900 font-medium outline-none opacity-60" value={formData.longitude} readOnly placeholder="0.000000" />
                    </div>
                  </div>
                  <div>
                    <label className="block text-[10px] font-semibold text-gray-400 uppercase tracking-wider ml-1 mb-3">Priority Level</label>
                    <div className="grid grid-cols-3 gap-3">
                      {priorities.map((p) => (
                        <button key={p.value} type="button" onClick={() => setFormData(prev => ({ ...prev, priority: p.value }))} className={`py-3 px-2 rounded-xl text-[10px] font-medium transition-all ${formData.priority === p.value ? 'bg-blue-600 text-white shadow-lg' : 'bg-gray-50 text-gray-400 hover:bg-gray-100'}`}>
                          {p.label}
                        </button>
                      ))}
                    </div>
                  </div>
                  <div>
                    <label className="block text-[10px] font-semibold text-gray-400 uppercase tracking-wider ml-1 mb-2">Evidence / Photos</label>
                    <label className="group relative block w-full aspect-video border-2 border-dashed border-gray-200 rounded-[2rem] hover:border-blue-300 hover:bg-blue-50/30 transition-all cursor-pointer overflow-hidden">
                      <input type="file" multiple accept="image/*" className="sr-only" onChange={handleImageUpload} />
                      <div className="absolute inset-0 flex flex-col items-center justify-center p-6 text-center">
                        <div className="w-16 h-16 bg-blue-100 text-blue-600 rounded-2xl flex items-center justify-center mb-4 group-hover:scale-110 transition-transform">
                          <PhotoIcon className="h-8 w-8" />
                        </div>
                        <p className="text-sm font-semibold text-gray-900">Upload Media</p>
                        <p className="text-xs text-gray-400 mt-1 font-medium">Click to browse or drag here</p>
                        {formData.images.length > 0 && (<div className="mt-4 px-4 py-2 bg-blue-600 text-white text-[10px] font-semibold uppercase rounded-full shadow-lg">{formData.images.length} Files Selected</div>)}
                      </div>
                    </label>
                  </div>
                </div>

                <div className="pt-4 flex flex-col sm:flex-row gap-4">
                  <button type="submit" disabled={loading} className="flex-1 px-8 py-5 bg-gradient-to-r from-blue-600 to-indigo-600 text-white rounded-[1.5rem] text-sm font-semibold uppercase shadow-xl hover:shadow-blue-300 transition-all disabled:opacity-50">
                    {loading ? 'Processing...' : 'Submit Report'}
                  </button>
                  <button type="button" onClick={() => navigate('/dashboard')} className="px-8 py-5 bg-white border border-gray-100 text-gray-400 rounded-[1.5rem] text-sm font-semibold uppercase hover:text-gray-900 active:scale-[0.98] transition-all">Cancel</button>
                </div>
              </form>
            </div>
          </div>
          <div className="mt-8 flex items-center justify-center space-x-2 text-gray-400">
            <CheckCircleIcon className="h-4 w-4" />
            <p className="text-[10px] font-medium text-gray-400 uppercase">End-to-End Encrypted Data Submission</p>
          </div>
        </div>
      </main>
    </div>
  );
};

export default ComplaintSubmission;
